#include <algorithm>\n#include <iostream>\n#include <string>\n#include <vector>\n\nint main() {\n  std::string word;\n  std::cin >> word;\n  std::vector<int> v(word.size(), 0);\n  v[0] = static_cast<int>(word.size());\n  int l = 0;\n  int r = l;\n  for (int i = 1; i < v[0]; i++) {\n    v[i] = std::min(r - i, v[i - l]);\n    if (v[i] < 0) {\n      v[i] = 0;\n    }\n    while (word[v[i]] == word[i + v[i]]) {\n      v[i]++;\n    }\n    if (i + v[i] <= r) {\n      continue;\n    }\n    r = i + v[i];\n    l = i;\n  }\n  for (int elem : v) {\n    std::cout << elem << ' ';\n  }\n  return 0;\n}